from crewai import Crew, Agent, Task
import re

def detect_loops(crew_history):
    agent_transitions = []
    for i, event in enumerate(crew_history):
        if 'delegated_to' in event:
            agent_transitions.append((event['from_agent'], event['to_agent']))

    # Detect cycles
    seen = set()
    for from_agent, to_agent in agent_transitions:
        path = (from_agent, to_agent)
        if path in seen:
            return True, f"Loop detected: {path}"
        seen.add(path)
    return False, "No loops"

